mapper.select:
SELECT c.cont_id AS contId, c.cont_name AS contName, c.organizer AS organizer, c.deadline AS deadline, c.logo_img AS logoImg, c.site_url AS siteUrl, c.category AS category, c.createdate AS createdate, CASE WHEN si.target_id IS NOT NULL THEN 'Y' ELSE 'N' END AS is_fav, CASE WHEN ui.target_id IS NOT NULL THEN 'Y' ELSE 'N' END AS is_skillup FROM contest c LEFT OUTER JOIN saved_item si ON si.target_type = 'CONTEST' AND si.target_id = TO_CHAR(c.cont_id) AND si.user_id = #{userId} LEFT OUTER JOIN user_ing ui ON ui.target_type = 'CONTEST' AND ui.target_id = TO_CHAR(c.cont_id) AND ui.user_id = #{userId}
(c.cont_name LIKE '%' || #{keyword} || '%' OR c.organizer LIKE '%' || #{keyword} || '%')
AND c.category = #{category}
AND c.deadline >= TRUNC(SYSDATE)
ORDER BY c.deadline ASC NULLS LAST
ORDER BY c.createdate DESC

SELECT COUNT(*)
FROM USER_ING
WHERE USER_ID = #{param1}
  AND TARGET_ID = #{param2}
  AND TARGET_TYPE = #{param3}

mapper.delete:
DELETE FROM USER_ING
WHERE USER_ID = #{param1}
  AND TARGET_ID = #{param2}
  AND TARGET_TYPE = #{param3}
